const item = $input.first();

let responseText = '';
try {
  responseText = item.json.candidates[0].content.parts[0].text;
} catch (error) {
  throw new Error('No se pudo extraer texto de Gemini: ' + error.message);
}

let jsonMatch = responseText.match(/\{[\s\S]*\}/);
if (!jsonMatch) {
  throw new Error('No se encontró JSON en la respuesta de Gemini');
}

let parsedContent;
try {
  parsedContent = JSON.parse(jsonMatch[0]);
} catch (error) {
  throw new Error('Error al parsear JSON: ' + error.message);
}

const pieFoto = (parsedContent.pie_foto || '').trim();
const descripcionPrenda = (parsedContent.descripcion_prenda || '').trim();
const promptImagen = (parsedContent.prompt_imagen || '').trim();

if (!pieFoto || !descripcionPrenda || !promptImagen) {
  throw new Error('Faltan campos requeridos en la respuesta de IA');
}

return [{
  json: {
    usuario_id: item.json.usuario_id,
    username: item.json.username,
    pie_foto: pieFoto,
    descripcion_prenda: descripcionPrenda,
    prompt_imagen: promptImagen,
    categoria: item.json.categoria,
    estilo: item.json.estilo,
    color: item.json.color
  }
}];

const item = $input.first();

const imagenBase64 = item.json.data || '';

if (!imagenBase64) {
  throw new Error('No se pudo obtener imagen en base64');
}

const imagenConFormato = imagenBase64.startsWith('data:') 
  ? imagenBase64 
  : `data:image/png;base64,${imagenBase64}`;

return [{
  json: {
    usuario_id: item.json.usuario_id,
    username: item.json.username,
    descripcion: item.json.pie_foto,
    descripcion_prenda: item.json.descripcion_prenda,
    foto_base64: imagenConFormato,
    categoria: item.json.categoria,
    estilo: item.json.estilo,
    color: item.json.color
  }
}];

const item = $input.first();

console.log('✅ Post demo creado exitosamente');
console.log(`Usuario: ${item.json.username} (ID: ${item.json.usuario_id})`);
console.log(`Categoría: ${item.json.categoria}`);
console.log(`Estilo: ${item.json.estilo}`);
console.log(`Color: ${item.json.color}`);

return [{
  json: {
    success: true,
    message: 'Post demo generado y guardado correctamente',
    usuario_id: item.json.usuario_id,
    username: item.json.username,
    post_id: item.json.id
  }
}];
